INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-4', 'ru', 'Облако нежности', 'Розовый кварц, лунный камень, фурнитура с позолотой', '890', 'Кольцо, собранное вручную из десятков мягких камней. Тактильная радость и напоминание о том, что ты заслуживаешь заботы.', 'Прикосновение заботы к себе.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-4', 'en', 'Cloud of Tenderness', 'Rose quartz, moonstone, gold-plated hardware', 'On request', 'A ring assembled by hand from dozens of soft stones. Tactile joy and a reminder that you deserve care.', 'A touch of care for yourself.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-4', 'kk', 'Нәзіктік бұлты', 'Қызғылт кварц, ай тасы, алтын жалатылған фурнитура', 'Сұраныс бойынша', 'Ондаған жұмсақ тастардан қолмен жиналған сақина. Тактильді қуаныш және сіздің қамқорлыққа лайық екендігіңіз туралы ескерту.', 'Өзіңізге деген қамқорлықтың жанасуы.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-1', 'ru', 'Колье', 'Натуральные камни, микс бусин, 18к фурнитура', 'По запросу', NULL, 'Яркость и стиль в одном колье.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-1', 'en', 'Necklace', 'Natural stones, mix of beads, 18k hardware', 'On request', NULL, 'Brightness and style in one necklace.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-1', 'kk', 'Алқа', 'Табиғи тастар, моншақтар миксі, 18к фурнитура', 'Сұраныс бойынша', NULL, 'Бір алқадағы жарықтық пен стиль.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-2', 'ru', 'Сестры по духу', 'Пастельные камни, фианиты, позолоченная фурнитура', '878', 'Мягкие оттенки, перетекающие друг в друга. Идеальный баланс формы и цвета, созданный руками с любовью к деталям.', 'Гармония, которую можно примерить.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-2', 'en', 'Sisters in Spirit', 'Pastel stones, cubic zirconia, gold-plated hardware', 'On request', 'Soft shades flowing into each other. The perfect balance of form and color, created by hands with love for details.', 'Harmony you can try on.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-2', 'kk', 'Рухтас апалы-сіңлілер', 'Пастельді тастар, фианиттер, алтын жалатылған фурнитура', 'Сұраныс бойынша', 'Бір-біріне ұласатын жұмсақ реңктер. Бөлшектерге деген сүйіспеншілікпен қолмен жасалған пішін мен түстің тамаша теңгерімі.', 'Өзіңіз киіп көруге болатын гармония.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-3', 'ru', 'Розовый закат', 'Пастельные бусины, ювелирный сплав, розовые фианиты', '950', 'Мягкий свет уходящего дня, застывший в камне. Для моментов, когда важно просто быть в моменте и слушать тишину.', 'Нежность, говорящая за тебя.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-3', 'en', 'Pink Sunset', 'Pastel beads, jewelry alloy, pink cubic zirconia', 'On request', 'The soft light of the fading day, frozen in stone. For moments when it is important to just be in the moment and listen to the silence.', 'Tenderness speaking for you.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-3', 'kk', 'Қызғылт күн батуы', 'Пастельді моншақтар, зергерлік қорытпа, қызғылт фианиттер', 'Сұраныс бойынша', 'Өтіп бара жатқан күннің таста қатып қалған жұмсақ сәулесі. Осы сәтте болып, үнсіздікті тыңдау маңызды болатын кездерге арналған.', 'Сіз үшін сөйлейтін нәзіктік.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-5', 'ru', 'Утренняя роса', 'Натуральные пастельные камни, ювелирный сплав, фианиты', 'По запросу', 'Переливы утреннего неба на твоем запястье. Это состояние гармонии и обещание того, что впереди только самое лучшее.', 'Мягкое свечение для души.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-5', 'en', 'Morning Dew', 'Natural pastel stones, jewelry alloy, cubic zirconia', 'On request', 'The iridescence of the morning sky on your wrist. It''s a state of harmony and a promise that only the best is ahead.', 'A soft glow for the soul.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('0001-5', 'kk', 'Таңғы шық', 'Табиғи пастельді тастар, зергерлік қорытпа, фианиттер', 'Сұраныс бойынша', 'Білегіңіздегі таңғы аспанның құбылуы. Бұл гармония күйі және алда тек жақсылық күтіп тұрғанына уәде.', 'Жанға арналған жұмсақ жарқырау.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0002-5', 'ru', 'Львиное сердце', 'Натуральный речной жемчуг, ювелирный сплав, эмаль, позолота', 'По запросу', 'Символ твоей внутренней силы, обрамленный в нежность природного жемчуга. Для дней, когда ты сама устанавливаешь правила игры.', 'Твой личный талисман уверенности.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0002-5', 'en', 'Lionheart', 'Natural freshwater pearl, jewelry alloy, enamel, gold plating', 'On request', 'A symbol of your inner strength, framed in the tenderness of natural pearls. For days when you set the rules of the game yourself.', 'Your personal talisman of confidence.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0002-5', 'kk', 'Арыстан жүрегі', 'Табиғи өзен меруерті, зергерлік қорытпа, эмаль, алтынмен қапталған', 'Сұраныс бойынша', 'Табиғи меруерттің нәзіктігімен көмкерілген ішкі күшіңіздің символы. Ойын ережелерін өзіңіз белгілейтін күндер үшін.', 'Сіздің жеке сенімділік тұмарыңыз.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-2', 'ru', 'Гранатовый сок', 'Барочные бусины (керамика/стекло), позолоченные вставки', '893', 'Неидеальные, живые формы глубокого винного цвета. Это вызов стерильности, манифест твоей дикой и настоящей природы.', 'Отказ от шаблонов.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-2', 'en', 'Pomegranate Juice', 'Baroque beads (ceramics/glass), gold-plated inserts', 'On request', 'Imperfect, lively shapes of deep wine color. It is a challenge to sterility, a manifesto of your wild and true nature.', 'Rejection of templates.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-2', 'kk', 'Анар шырыны', 'Барокко моншақтары (керамика/шыны), алтын жалатылған кірістірулер', 'Сұраныс бойынша', 'Терең шарап түсінің мінсіз емес, жанды пішіндері. Бұл стерильділікке шақыру, сіздің жабайы және шынайы табиғатыңыздың манифесі.', 'Шаблондардан бас тарту.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-1', 'ru', 'Колье', 'Майорка-барокко, позолоченная фурнитура', 'По запросу', NULL, 'Вечная классика в новом прочтении.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-1', 'en', 'Necklace', 'Mallorca baroque, gold-plated hardware', 'On request', NULL, 'Eternal classic in a new reading.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0003-1', 'kk', 'Алқа', 'Майорка-барокко, алтын жалатылған фурнитура', 'Сұраныс бойынша', NULL, 'Жаңа оқылымдағы мәңгілік классика.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0004-2', 'ru', 'Белые пески', 'Белый матовый агат, ювелирный сплав, кристаллы', 'По запросу', 'Чистота формы и спокойствие матового камня. Браслет, который словно просит остановиться, сделать глубокий вдох и прислушаться к себе.', 'Идеальная база для спокойных дней.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0004-2', 'en', 'White Sands', 'White matte agate, jewelry alloy, crystals', 'On request', 'Purity of form and the calmness of matte stone. A bracelet that seems to ask you to stop, take a deep breath, and listen to yourself.', 'The perfect base for calm days.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0004-2', 'kk', 'Ақ құмдар', 'Ақ күңгірт агат, зергерлік қорытпа, кристалдар', 'Сұраныс бойынша', 'Пішіннің тазалығы және күңгірт тастың тыныштығы. Тоқтап, терең дем алып, өзіңізді тыңдауға шақыратын білезік.', 'Тыныш күндерге арналған мінсіз негіз.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0005-2', 'ru', 'Сладкий нектар', 'Натуральный барочный жемчуг, перламутр, фианиты, позолота', '1152', 'Природная асимметрия крупного жемчуга and дерзкий символ свободы на твоем запястье. Замедляйся и наслаждайся каждым прикосновением света.', 'Свобода быть собой в каждой детали.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0005-2', 'en', 'Sweet Nectar', 'Natural baroque pearl, mother-of-pearl, cubic zirconia, gold plating', 'On request', 'The natural asymmetry of large pearls and a bold symbol of freedom on your wrist. Slow down and enjoy every touch of light.', 'The freedom to be yourself in every detail.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0005-2', 'kk', 'Тәтті шырын', 'Табиғи барокко меруерті, перламутр, фианиттер, алтынмен қапталған', 'Сұраныс бойынша', 'Ірі меруерттің табиғи асимметриясы және білегіңіздегі еркіндіктің батыл символы. Асықпаңыз және жарықтың әрбір жанасуынан ләззат алыңыз.', 'Әр бөлшекте өзің болу еркіндігі.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0006-2', 'ru', 'Теплое течение', 'Речной жемчуг, ювелирный сплав, цветная эмаль', 'По запросу', 'Каждый шарм — это маленькая глава твоей книги о лете. Мы сохранили для тебя состояние расслабленности и теплого песка под ногами.', 'Забери лето с собой.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0006-2', 'en', 'Warm Current', 'Freshwater pearl, jewelry alloy, colored enamel', 'On request', 'Every charm is a small chapter of your book about summer. We have preserved for you the state of relaxation and warm sand under your feet.', 'Take summer with you.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0006-2', 'kk', 'Жылы ағыс', 'Өзен меруерті, зергерлік қорытпа, түрлі-түсті эмаль', 'Сұраныс бойынша', 'Әрбір тұмар — жаз туралы кітабыңыздың кішкентай тарауы. Біз сіз үшін релаксация күйін және аяғыңыздың астындағы жылы құмды сақтап қалдық.', 'Жазды өзіңмен бірге алып жүр.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0007-2', 'ru', 'Полет фантазии', 'Барочный жемчуг разных форм, красные фианиты, позолота', '930', 'Два яруса несовершенного, живого жемчуга и дерзкий алый акцент. Для тех, кто ценит ручной труд и уникальность каждого изгиба.', 'Естественность без фильтров.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0007-2', 'en', 'Flight of Fancy', 'Baroque pearls of various shapes, red cubic zirconia, gold plating', 'On request', 'Two tiers of imperfect, lively pearls and a daring scarlet accent. For those who value handmade work and the uniqueness of every curve.', 'Naturalness without filters.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0007-2', 'kk', 'Қиял самғауы', 'Әртүрлі пішіндегі барокко меруерті, қызыл фианиттер, алтынмен қапталған', 'Сұраныс бойынша', 'Мінсіз емес, жанды меруерттің екі қабаты және батыл қызыл екпін. Қол еңбегін және әрбір қисықтың бірегейлігін бағалайтындар үшін.', 'Сүзгісіз табиғилық.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0008-2', 'ru', 'Шепот волн', 'Перламутр, барочный жемчуг, позолота, цветная эмаль', 'По запросу', 'Собери коллекцию воспоминаний о соленом ветре и бескрайнем горизонте. Пусть каждый элемент возвращает тебя в состояние абсолютной свободы.', 'Твое море всегда с тобой.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0008-2', 'en', 'Whisper of Waves', 'Mother-of-pearl, baroque pearl, gold plating, colored enamel', 'On request', 'Gather a collection of memories of the salty wind and the endless horizon. Let each element bring you back to a state of absolute freedom.', 'Your sea is always with you.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0008-2', 'kk', 'Толқындар сыбдыры', 'Перламутр, барокко меруерті, алтынмен қапталған, түрлі-түсті эмаль', 'Сұраныс бойынша', 'Тұзды жел мен шексіз көкжиек туралы естеліктер топтамасын жинаңыз. Әрбір элемент сізді абсолютті еркіндік күйіне қайтарсын.', 'Сенің теңізің әрқашан өзіңмен бірге.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0009-2', 'ru', 'Зов горизонта', 'Речной жемчуг, ювелирный сплав, эмаль', 'По запросу', 'Билет в лето, который всегда с тобой. Жемчужные линии в сочетании с талисманами странствий для тех, кто не мыслит себя без движения.', 'Твоя путеводная звезда.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0009-2', 'en', 'Call of the Horizon', 'Freshwater pearl, jewelry alloy, enamel', 'On request', 'A ticket to summer that is always with you. Pearl lines combined with travel talismans for those who cannot imagine themselves without movement.', 'Your guiding star.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0009-2', 'kk', 'Көкжиек шақыруы', 'Өзен меруерті, зергерлік қорытпа, эмаль', 'Сұраныс бойынша', 'Әрқашан өзіңізбен бірге жүретін жазға билет. Өзін қозғалыссыз елестете алмайтындарға арналған саяхат тұмарларымен үйлесетін меруерт сызықтар.', 'Сенің темірқазығың.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0013-2', 'ru', 'Бирюзовая лагуна', 'Натуральный жемчуг, голубая эмаль, позолоченные подвески', 'По запросу', 'Цвет прозрачной воды и теплый блеск золота. Замедлись и почувствуй, как дыхание становится ровнее, а мысли светлее.', 'Твоя личная стихия.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0013-2', 'en', 'Turquoise Lagoon', 'Natural pearl, blue enamel, gold-plated pendants', 'On request', 'The color of clear water and the warm gleam of gold. Slow down and feel your breathing become more even and your thoughts clearer.', 'Your personal element.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0013-2', 'kk', 'Көгілдір лагуна', 'Табиғи меруерт, көк эмаль, алтын жалатылған кулондар', 'Сұраныс бойынша', 'Мөлдір судың түсі және алтынның жылы жарқырауы. Баяулаңыз және тынысыңыздың қалыпқа түсіп, ойларыңыздың жарқын болғанын сезініңіз.', 'Сіздің жеке стихияңыз.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-1', 'ru', 'Тайны глубин', 'Крупный жемчуг, позолоченные цепи, эмалевые шармы', '2100', 'Роскошное падение золотых нитей и белоснежная эмаль морских символов. Состояние торжественной уверенности перед выходом в свет.', 'Отражение звездного неба в океане.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-1', 'en', 'Secrets of the Depths', 'Large pearl, gold-plated chains, enamel charms', 'On request', 'A luxurious fall of golden threads and snow-white enamel of sea symbols. A state of solemn confidence before stepping out.', 'Reflection of the starry sky in the ocean.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-1', 'kk', 'Тұңғиық құпиялары', 'Ірі меруерт, алтын жалатылған шынжырлар, эмаль тұмарлары', 'Сұраныс бойынша', 'Алтын жіптердің сәнді құлауы және теңіз символдарының аппақ эмалі. Көпшілік алдына шығар алдындағы салтанатты сенімділік күйі.', 'Мұхиттағы жұлдызды аспанның көрінісі.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-5', 'ru', 'Сет: колье и браслет', 'Натуральный жемчуг, позолоченная фурнитура, ювелирная эмаль', 'По запросу', NULL, 'Полный образ для берега океана.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-5', 'en', 'Set: Necklace and Bracelet', 'Natural pearl, gold-plated hardware, jewelry enamel', 'On request', NULL, 'Complete look for the ocean shore.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0014-5', 'kk', 'Жинақ: алқа және білезік', 'Табиғи меруерт, алтын жалатылған фурнитура, зергерлік эмаль', 'Сұраныс бойынша', NULL, 'Мұхит жағалауына арналған толық бейне.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0010-1', 'ru', 'Островной побег', 'Белый агат, позолоченная фурнитура, эмаль', '1458', 'Маленькие картины, запечатлевшие мгновения покоя. Надевай, когда городу не хватает солнца, а душе — неспешного ритма тропиков.', 'Магия медленной жизни в каждом шарме.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0010-1', 'en', 'Island Escape', 'White agate, gold-plated hardware, enamel', 'On request', 'Small pictures capturing moments of peace. Wear them when the city lacks sun, and the soul craves the unhurried rhythm of the tropics.', 'The magic of slow living in every charm.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0010-1', 'kk', 'Аралға қашу', 'Ақ агат, алтын жалатылған фурнитура, эмаль', 'Сұраныс бойынша', 'Тыныштық сәттерін бейнелейтін кішкентай суреттер. Қалаға күн жетіспегенде, ал жан тропиктердің асықпайтын ырғағын қалағанда тағыңыз.', 'Әрбір тұмардағы баяу өмір сиқыры.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0011-1', 'ru', 'Золото Нила', 'Белый матовый агат, ювелирный сплав с позолотой', '1360', 'Аристократичная многослойность и профиль великой царицы. Носи как символ своего безусловного достоинства.', 'Царственная осанка и внутренний свет.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0011-1', 'en', 'Gold of the Nile', 'White matte agate, jewelry alloy with gold plating', 'On request', 'Aristocratic layering and the profile of a great queen. Wear it as a symbol of your unconditional dignity.', 'Regal posture and inner light.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0011-1', 'kk', 'Ніл алтыны', 'Ақ күңгірт агат, алтын жалатылған зергерлік қорытпа', 'Сұраныс бойынша', 'Ақсүйектік көпқабаттылық және ұлы патшайымның профилі. Мұны сіздің сөзсіз қадір-қасиетіңіздің белгісі ретінде тағыңыз.', 'Патшайымға тән мүсін және ішкі нұр.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-5', 'ru', 'Наивная смелость', 'Натуральный жемчуг, замок-тогл, позолота, фианиты', 'По запросу', 'Соединение классического жемчуга и ироничного кулона. Для девушек, которые умеют быть серьезными, но выбирают игру.', 'Правил больше нет.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-5', 'en', 'Naive Courage', 'Natural pearl, toggle clasp, gold plating, cubic zirconia', 'On request', 'A combination of classic pearls and an ironic pendant. For girls who know how to be serious but choose to play.', 'There are no more rules.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-5', 'kk', 'Аңғал батылдық', 'Табиғи меруерт, тогл ілгегі, алтынмен қапталған, фианиттер', 'Сұраныс бойынша', 'Классикалық меруерт пен ирониялық кулонның үйлесімі. Байсалды болуды білетін, бірақ ойынды таңдайтын қыздарға арналған.', 'Енді ережелер жоқ.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-3', 'ru', 'Игривая искра', 'Ювелирный сплав, позолота, кубический цирконий, эмаль', '900', 'Напоминание о том, что внутри каждой из нас живет девчонка, готовая смеяться без повода. Надевай, когда хочется сбросить маски и позволить себе легкость.', 'Добавь в будни каплю беззаботности.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-3', 'en', 'Playful Spark', 'Jewelry alloy, gold plating, cubic zirconia, enamel', 'On request', 'A reminder that inside each of us lives a girl ready to laugh for no reason. Wear it when you want to drop the masks and allow yourself some lightness.', 'Add a drop of carefreeness to your everyday life.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0012-3', 'kk', 'Ойнақы ұшқын', 'Зергерлік қорытпа, алтынмен қапталған, текше цирконий, эмаль', 'Сұраныс бойынша', 'Әрқайсымыздың ішімізде себепсіз күлуге дайын қыз өмір сүретінін еске салады. Бетперделерді тастап, өзіңізге жеңілдік сыйлағыңыз келгенде тағыңыз.', 'Күнделікті өмірге қамсыздық тамшысын қосыңыз.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('winter-0015-1', 'ru', 'Колье «Снежное Сияние»', 'Матовый аквамариновый кварц, золочёная фурнитура, подвеска «Снежинка» с фианитами', 'По запросу', NULL, 'Холодное сияние зимнего утра в изящном украшении.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('winter-0015-1', 'en', 'Snowy Glow Necklace', 'Matte aquamarine quartz, gold-plated hardware, snowflake pendant with cz', 'On request', NULL, 'The cold glow of a winter morning in an elegant jewelry piece.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('winter-0015-1', 'kk', '«Қар шұғыласы» алқасы', 'Күңгірт аквамарин кварцы, алтын жалатылған фурнитура, фианиттері бар «Қар ұшқыны» кулоны', 'Сұраныс бойынша', NULL, 'Талғампаз әшекейдегі қысқы таңның суық шұғыласы.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0016-1', 'ru', 'Дикая грация', 'Натуральный жемчуг, ювелирный сплав с позолотой, изумрудные фианиты', '1650', 'Холодный блеск проницательных глаз и благородная теплота жемчуга. Украшение, которое говорит о твоем свободолюбивом характере без единого слова.', 'Характер, который невозможно приручить.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0016-1', 'en', 'Wild Grace', 'Natural pearl, gold-plated jewelry alloy, emerald cubic zirconia', 'On request', 'The cold gleam of piercing eyes and the noble warmth of pearls. Jewelry that speaks of your freedom-loving character without a single word.', 'A character that cannot be tamed.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0016-1', 'kk', 'Жабайы грация', 'Табиғи меруерт, алтынмен қапталған зергерлік қорытпа, изумруд фианиттері', 'Сұраныс бойынша', 'Өткір көздердің суық жылтыры және меруерттің текті жылуы. Сіздің еркіндік сүйгіш мінезіңіз туралы бірде-бір сөзсіз айтатын әшекей.', 'Бағындыру мүмкін емес мінез.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0017-1', 'ru', 'Первозданный инстинкт', 'Натуральный тигровый глаз, ювелирный сплав с позолотой, фианиты', '1360', 'Глубокая магия природного камня пробуждает внутреннюю энергию. Стань создательницей своих правил и хозяйкой своей реальности.', 'Энергия, которую можно ощутить кожей.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0017-1', 'en', 'Primal Instinct', 'Natural tiger''s eye, gold-plated jewelry alloy, cubic zirconia', 'On request', 'The deep magic of the natural stone awakens inner energy. Become the creator of your own rules and the mistress of your reality.', 'Energy that can be felt by the skin.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0017-1', 'kk', 'Бастапқы инстинкт', 'Табиғи жолбарыс көзі, алтынмен қапталған зергерлік қорытпа, фианиттер', 'Сұраныс бойынша', 'Табиғи тастың терең сиқыры ішкі энергияны оятады. Өз ережелеріңіздің жасаушысы және өз шындығыңыздың қожайыны болыңыз.', 'Терімен сезінетін энергия.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-2', 'ru', 'Вечный странник', 'Цветной полупрозрачный кварц/агат, эмаль, позолота', '823', 'Яркие леденцовые камни и мечты о новых городах. Это не просто браслет, это твой личный компас, указывающий на радость.', 'Жизнь в движении.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-2', 'en', 'Eternal Wanderer', 'Colored translucent quartz/agate, enamel, gold plating', 'On request', 'Bright candy-colored stones and dreams of new cities. This is not just a bracelet, it''s your personal compass pointing to joy.', 'Life in motion.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-2', 'kk', 'Мәңгілік кезбе', 'Түрлі-түсті мөлдір кварц/агат, эмаль, алтынмен қапталған', 'Сұраныс бойынша', 'Жарқын кәмпит тастары және жаңа қалалар туралы армандар. Бұл жай ғана білезік емес, қуанышты көрсететін жеке компасыңыз.', 'Қозғалыстағы өмір.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-3', 'ru', 'Сад чудес', 'Натуральный кварц, цветные фианиты, позолота', 'По запросу', 'Рассыпанные цветы и нежные оттенки. Позволь себе быть разной, меняя детали так же легко, как меняется настроение весеннего дня.', 'Создай свою уникальную историю.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-3', 'en', 'Garden of Wonders', 'Natural quartz, colored cubic zirconia, gold plating', 'On request', 'Scattered flowers and delicate shades. Allow yourself to be different, changing details as easily as the mood of a spring day changes.', 'Create your own unique story.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0018-3', 'kk', 'Кереметтер бағы', 'Табиғи кварц, түрлі-түсті фианиттер, алтынмен қапталған', 'Сұраныс бойынша', 'Шашыраңқы гүлдер мен нәзік реңктер. Көктемгі күннің көңіл-күйі қаншалықты оңай өзгерсе, бөлшектерді де соншалықты оңай өзгертіп, әртүрлі болуға рұқсат етіңіз.', 'Өзіңіздің қайталанбас тарихыңызды жасаңыз.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0019-1', 'ru', 'Поцелуй нимфы', 'Натуральный жемчуг, резной перламутр, позолота, фианиты', '1690', 'Изящный лист, вырезанный из перламутра, на фоне чистого жемчуга. Замедлись, чтобы услышать шелест леса и дыхание природы.', 'Естественная эстетика в каждом изгибе.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0019-1', 'en', 'Nymph''s Kiss', 'Natural pearl, carved mother-of-pearl, gold plating, cubic zirconia', 'On request', 'A graceful leaf carved from mother-of-pearl against a background of pure pearls. Slow down to hear the rustle of the forest and the breath of nature.', 'Natural aesthetics in every curve.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0019-1', 'kk', 'Нимфаның сүйісуі', 'Табиғи меруерт, ойылған перламутр, алтынмен қапталған, фианиттер', 'Сұраныс бойынша', 'Таза меруерт аясындағы перламутрдан ойылған әсем жапырақ. Орманныңбдыры мен табиғаттың тынысын есту үшін баяулаңыз.', 'Әрбір қисықтағы табиғи эстетика.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0020-5', 'ru', 'Ритм страсти', 'Стекло/эмаль, ювелирный сплав, позолота', '2490', 'Глубокий карминный оттенок для моментов, когда ты выбираешь звучать громко и жить на полную. Это не просто акцент, это твое состояние влюбленности в жизнь.', 'Для тех, кто не боится своих чувств.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0020-5', 'en', 'Rhythm of Passion', 'Glass/enamel, jewelry alloy, gold plating', 'On request', 'A deep carmine shade for moments when you choose to sound loud and live life to the fullest. It''s not just an accent, it''s your state of being in love with life.', 'For those who are not afraid of their feelings.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0020-5', 'kk', 'Құмарлық ырғағы', 'Шыны/эмаль, зергерлік қорытпа, алтынмен қапталған', 'Сұраныс бойынша', 'Өмірді барынша сүруді және жарқын болуды таңдаған сәттерге арналған терең кармин реңкі. Бұл жай ғана екпін емес, бұл сіздің өмірге ғашық күйіңіз.', 'Өз сезімдерінен қорықпайтындар үшін.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0021-5', 'ru', 'Неизменная классика', 'Натуральный речной жемчуг, красные кристаллы, позолота', 'По запросу', 'Встреча благородной сдержанности и яркого темперамента. Идеально для моментов, когда ты хочешь чувствовать себя безупречно уверенной.', 'Для историй, которые запоминаются навсегда.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0021-5', 'en', 'Timeless Classic', 'Natural freshwater pearl, red crystals, gold plating', 'On request', 'A meeting of noble restraint and bright temperament. Perfect for moments when you want to feel flawlessly confident.', 'For stories that are remembered forever.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('symbol-0021-5', 'kk', 'Өзгермес классика', 'Табиғи өзен меруерті, қызыл кристалдар, алтынмен қапталған', 'Сұраныс бойынша', 'Асыл ұстамдылық пен жарқын темпераменттің кездесуі. Өзіңізді мінсіз сенімді сезінгіңіз келетін сәттерге арналған.', 'Мәңгі есте қалатын оқиғалар үшін.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0022-5', 'ru', 'Тайная тропа', 'Ювелирный сплав, позолота, прозрачные фианиты', '1240', 'Детализация, достойная восхищения. Твое личное напоминание о том, что настоящая красота кроется в мельчайших деталях и упорстве на пути к мечте.', 'Особенная красота для внимательных.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0022-5', 'en', 'Secret Path', 'Jewelry alloy, gold plating, clear cubic zirconia', 'On request', 'Detailing worthy of admiration. Your personal reminder that true beauty lies in the smallest details and perseverance on the way to your dream.', 'Special beauty for the attentive.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0022-5', 'kk', 'Құпия соқпақ', 'Зергерлік қорытпа, алтынмен қапталған, мөлдір фианиттер', 'Сұраныс бойынша', 'Таңдануға тұрарлық бөлшектер. Нағыз сұлулық ең кішкентай бөлшектерде және арманға бастар жолдағы табандылықта екендігі туралы жеке ескертуіңіз.', 'Мұқият жандарға арналған ерекше сұлулық.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0023-2', 'ru', 'Дух саванны', 'Натуральный тигровый глаз, позолота, кубический цирконий', '1083', 'Теплые, землистые оттенки камня заземляют и дарят уверенность. Сильный характер в каждой бусине ручной сборки.', 'Сила, подаренная природой.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0023-2', 'en', 'Spirit of the Savannah', 'Natural tiger''s eye, gold plating, cubic zirconia', 'On request', 'The warm, earthy shades of the stone ground you and give confidence. A strong character in every hand-assembled bead.', 'Strength gifted by nature.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('summer-0023-2', 'kk', 'Саванна рухы', 'Табиғи жолбарыс көзі, алтынмен қапталған, текше цирконий', 'Сұраныс бойынша', 'Тастың жылы, жер реңктері сенімділік сыйлайды. Қолмен жиналған әрбір моншақтағы күшті мінез.', 'Табиғат сыйлаған күш.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-1', 'ru', 'Аметистовый сон', 'Натуральный аметист (крошка и огранка), позолоченная цепь', '1655', 'Загадочный фиолетовый свет камня балансирует эмоции и дарит внутреннюю тишину. Истинная красота природы, не тронутая суетой.', 'Глубина, в которой хочется раствориться.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-1', 'en', 'Amethyst Dream', 'Natural amethyst (chips and faceted), gold-plated chain', 'On request', 'The mysterious purple light of the stone balances emotions and gives inner silence. The true beauty of nature, untouched by fuss.', 'A depth you want to dissolve in.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-1', 'kk', 'Аметист түсі', 'Табиғи аметист (ұнтақ және қырлы), алтын жалатылған шынжыр', 'Сұраныс бойынша', 'Тастың жұмбақ күлгін сәулесі эмоцияларды теңестіреді және ішкі тыныштық береді. Күйбең тірлік тимеген табиғаттың нағыз сұлулығы.', 'Сіңіп кеткің келетін тереңдік.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-2', 'ru', 'Аметистовый сон', 'Натуральный аметист (крошка и огранка), позолоченная цепь', '1655', 'Загадочный фиолетовый свет камня балансирует эмоции и дарит внутреннюю тишину. Истинная красота природы, не тронутая суетой.', 'Глубина, в которой хочется раствориться.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-2', 'en', 'Amethyst Dream', 'Natural amethyst (chips and faceted), gold-plated chain', 'On request', 'The mysterious purple light of the stone balances emotions and gives inner silence. The true beauty of nature, untouched by fuss.', 'A depth you want to dissolve in.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-2', 'kk', 'Аметист түсі', 'Табиғи аметист (ұнтақ және қырлы), алтын жалатылған шынжыр', 'Сұраныс бойынша', 'Тастың жұмбақ күлгін сәулесі эмоцияларды теңестіреді және ішкі тыныштық береді. Күйбең тірлік тимеген табиғаттың нағыз сұлулығы.', 'Сіңіп кеткің келетін тереңдік.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-3', 'ru', 'Аметистовый сон', 'Натуральный аметист (крошка и огранка), позолоченная цепь', '1655', 'Загадочный фиолетовый свет камня балансирует эмоции и дарит внутреннюю тишину. Истинная красота природы, не тронутая суетой.', 'Глубина, в которой хочется раствориться.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-3', 'en', 'Amethyst Dream', 'Natural amethyst (chips and faceted), gold-plated chain', 'On request', 'The mysterious purple light of the stone balances emotions and gives inner silence. The true beauty of nature, untouched by fuss.', 'A depth you want to dissolve in.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-3', 'kk', 'Аметист түсі', 'Табиғи аметист (ұнтақ және қырлы), алтын жалатылған шынжыр', 'Сұраныс бойынша', 'Тастың жұмбақ күлгін сәулесі эмоцияларды теңестіреді және ішкі тыныштық береді. Күйбең тірлік тимеген табиғаттың нағыз сұлулығы.', 'Сіңіп кеткің келетін тереңдік.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-4', 'ru', 'Сердце мага', 'Ювелирный сплав, позолота, ограненный аметист', 'По запросу', 'Фактурное кольцо с камнем, который ловит каждый луч света. Твое тайное оружие в искусстве оставлять незабываемое впечатление.', 'Магия в твоих руках.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-4', 'en', 'Heart of a Mage', 'Jewelry alloy, gold plating, faceted amethyst', 'On request', 'A textured ring with a stone that catches every ray of light. Your secret weapon in the art of leaving an unforgettable impression.', 'Magic in your hands.');
INSERT INTO product_translations (product_id, lang, name, material, price_display, description, look_caption) VALUES ('spring-0024-4', 'kk', 'Сиқыршы жүрегі', 'Зергерлік қорытпа, алтынмен қапталған, қырлы аметист', 'Сұраныс бойынша', 'Әрбір жарық сәулесін ұстайтын тасы бар фактуралық сақина. Ұмытылмас әсер қалдыру өнеріндегі сіздің құпия қаруыңыз.', 'Сиқыр сенің қолыңда.');
